CREATE VIEW `ads_report_AB_experiment_view` (`dt` COMMENT "统计周期", `app_lang_id` COMMENT "界面语言", `page_name` COMMENT "页面名称", `recommet_unt` COMMENT "推荐人数", `read_unt` COMMENT "阅读人数（曝光之后20秒内有阅读）", `consume_unt` COMMENT "消耗人数", `total_consume` COMMENT "总消耗", `total_csum_num` COMMENT "解锁章节数", `csum_avg_exposure` COMMENT "人均消费/曝光", `csum_avg_read` COMMENT "阅读转化率", `csum_avg_csum` COMMENT "消费转化率", `user_money_consume` COMMENT "阅币消耗", `user_money_consume_unt` COMMENT "阅币消耗人数", `charge_unt` COMMENT "充值人数", `charge_money` COMMENT "充值金额", `etl_time` COMMENT "处理时间") AS SELECT `ads`.`ads_report_AB_experiment`.`dt`, `ads`.`ads_report_AB_experiment`.`app_lang_id`, CASE WHEN (`ads`.`ads_report_AB_experiment`.`page_name` = 'may_like-compare_group') THEN '猜你喜欢-对照组' WHEN (`ads`.`ads_report_AB_experiment`.`page_name` = 'may_like-experimental_group') THEN '猜你喜欢-实验组' ELSE '' END AS `page_name`, `ads`.`ads_report_AB_experiment`.`recommet_unt`, `ads`.`ads_report_AB_experiment`.`read_unt`, `ads`.`ads_report_AB_experiment`.`consume_unt`, `ads`.`ads_report_AB_experiment`.`total_consume`, `ads`.`ads_report_AB_experiment`.`total_csum_num`, `ads`.`ads_report_AB_experiment`.`csum_avg_exposure`, `ads`.`ads_report_AB_experiment`.`csum_avg_read`, `ads`.`ads_report_AB_experiment`.`csum_avg_csum`, `ads`.`ads_report_AB_experiment`.`user_money_consume`, `ads`.`ads_report_AB_experiment`.`user_money_consume_unt`, `ads`.`ads_report_AB_experiment`.`charge_unt`, `ads`.`ads_report_AB_experiment`.`charge_money`, `ads`.`ads_report_AB_experiment`.`etl_time`
FROM `ads`.`ads_report_AB_experiment`;